/* CLOCK TICK EASTER EGG (L1-specific) */
var ClockTick = function() {
  var ticks = [];
  for (var i = 0; i < 12; i++) {
    var angle = (i * 30) * Math.PI / 180;
    var x1 = 50 + 38 * Math.cos(angle - Math.PI/2);
    var y1 = 50 + 38 * Math.sin(angle - Math.PI/2);
    var x2 = 50 + 44 * Math.cos(angle - Math.PI/2);
    var y2 = 50 + 44 * Math.sin(angle - Math.PI/2);
    var tc = (i === 3) ? B.brandGreen : B.muted;
    var op = (i === 3) ? 0.6 : 0.15;
    var sw = (i === 3) ? 2 : 1;
    ticks.push(React.createElement("line", { key: i, x1: x1, y1: y1, x2: x2, y2: y2, stroke: tc, strokeWidth: sw, opacity: op }));
  }
  return React.createElement("div", { style: { position: "absolute", top: 12, right: 12, width: 50, height: 50 } },
    React.createElement("svg", { width: 50, height: 50, viewBox: "0 0 100 100" }, ticks)
  );
};

